// Processor for SAML Responses
class SAMLResponseProcessor {

    private DocumentBuilderFactory dbf;

    public SAMLResponseProcessor() {
        dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true); // Crucial for handling XML namespaces
    }

    // Decodes a Base64 encoded SAML response string.
    // It attempts URL-decoding first, then direct Base64 decoding.
    public String decodeSAMLResponse(String encodedResponse) {
        try {
            // First, try URL decoding (common if passed as query param)
            String urlDecoded = URLDecoder.decode(encodedResponse, StandardCharsets.UTF_8.name());
            byte[] decodedBytes = Base64.getDecoder().decode(urlDecoded);
            return new String(decodedBytes, StandardCharsets.UTF_8);
        } catch (UnsupportedEncodingException e) {
            // This should not happen with StandardCharsets.UTF_8
            System.err.println("Encoding not supported: " + e.getMessage());
            return null;
        } catch (IllegalArgumentException e) {
            // If URL decoding failed or resulted in invalid Base64, try direct Base64 decoding
            try {
                byte[] decodedBytes = Base64.getDecoder().decode(encodedResponse);
                return new String(decodedBytes, StandardCharsets.UTF_8);
            } catch (IllegalArgumentException base64e) {
                System.err.println("Invalid Base64 string: " + base64e.getMessage());
                return null;
            }
        }
    }

    // Processes the raw SAML XML string to extract user information and create a session.
    public UserSession processSAMLResponse(String samlResponseXml) throws SAMLProcessingException {
        if (samlResponseXml == null || samlResponseXml.trim().isEmpty()) {
            throw new SAMLProcessingException("SAML Response XML cannot be null or empty.");
        }

        try {
            DocumentBuilder db = dbf.newDocumentBuilder();
            // Parse the XML string into a Document object
            Document doc = db.parse(new ByteArrayInputStream(samlResponseXml.getBytes(StandardCharsets.UTF_8)));
            doc.getDocumentElement().normalize();

            // 1. Check the root element to ensure it's a SAML 2.0 Response
            Element responseElement = doc.getDocumentElement();
            if (!"Response".equals(responseElement.getLocalName()) ||
                !"urn:oasis:names:tc:SAML:2.0:protocol".equals(responseElement.getNamespaceURI())) {
                throw new SAMLProcessingException("Root element is not a SAML 2.0 Protocol Response or has incorrect namespace.");
            }

            // 2. Extract Assertion(s) - a SAML Response can contain multiple assertions,
            // but typically for IdP-initiated SSO, there's one.
            NodeList assertionNodes = responseElement.getElementsByTagNameNS("urn:oasis:names:tc:SAML:2.0:assertion", "Assertion");

            if (assertionNodes.getLength() == 0) {
                throw new SAMLProcessingException("No Assertion element found in SAML Response. Cannot authenticate.");
            }

            // For simplicity, we process the first assertion found.
            // In a real application, you might iterate or have specific logic for multiple assertions.
            Element assertionElement = (Element) assertionNodes.item(0);

            // Extract principal name (e.g., username, email)
            String principalName = extractPrincipalName(assertionElement);
            // Extract user attributes
            Map<String, List<String>> userAttributes = extractUserAttributes(assertionElement);
            // Use the Assertion ID as a potential session identifier
            String sessionId = assertionElement.getAttribute("ID");

            // 3. Create an authenticated session object
            return new UserSession(principalName, userAttributes, sessionId);

        } catch (ParserConfigurationException e) {
            throw new SAMLProcessingException("Error configuring XML parser: " + e.getMessage(), e);
        } catch (SAXException e) {
            throw new SAMLProcessingException("Error parsing SAML XML (malformed XML): " + e.getMessage(), e);
        } catch (IOException e) {
            throw new SAMLProcessingException("I/O error reading SAML XML: " + e.getMessage(), e);
        }
    }

    // Extracts the principal's name from the Assertion's Subject/NameID.
    private String extractPrincipalName(Element assertionElement) throws SAMLProcessingException {
        NodeList subjectNodes = assertionElement.getElementsByTagNameNS("urn:oasis:names:tc:SAML:2.0:assertion", "Subject");
        if (subjectNodes.getLength() == 0) {
            throw new SAMLProcessingException("No Subject element found in Assertion.");
        }
        Element subjectElement = (Element) subjectNodes.item(0);

        NodeList nameIDNodes = subjectElement.getElementsByTagNameNS("urn:oasis:names:tc:SAML:2.0:assertion", "NameID");
        if (nameIDNodes.getLength() > 0) {
            return nameIDNodes.item(0).getTextContent();
        }

        throw new SAMLProcessingException("No NameID found in Subject element within Assertion.");
    }

    // Extracts user attributes from the Assertion's AttributeStatement.
    private Map<String, List<String>> extractUserAttributes(Element assertionElement) {
        Map<String, List<String>> attributes = new HashMap<>();
        NodeList attributeStatementNodes = assertionElement.getElementsByTagNameNS("urn:oasis:names:tc:SAML:2.0:assertion", "AttributeStatement");

        if (attributeStatementNodes.getLength() == 0) {
            return attributes; // No attributes found
        }

        // Again, assume one AttributeStatement for simplicity
        Element attributeStatementElement = (Element) attributeStatementNodes.item(0);
        NodeList attributeNodes = attributeStatementElement.getElementsByTagNameNS("urn:oasis:names:tc:SAML:2.0:assertion", "Attribute");

        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attributeElement = (Element) attributeNodes.item(i);
            String attributeName = attributeElement.getAttribute("Name");
            if (attributeName == null || attributeName.trim().isEmpty()) {
                continue; // Skip attributes without a name
            }

            NodeList attributeValueNodes = attributeElement.getElementsByTagNameNS("urn:oasis:names:tc:SAML:2.0:assertion", "AttributeValue");
            List<String> values = new ArrayList<>();
            for (int j = 0; j < attributeValueNodes.getLength(); j++) {
                values.add(attributeValueNodes.item(j).getTextContent());
            }
            attributes.put(attributeName, values);
        }
        return attributes;
    }
}

